#include <stdio.h>

void swap(int *a, int *b) {
  int temp = *a;
  *a = *b;
  *b = temp;
}

void increment(int *x) {
  (*x)++;
}

int main() {
  int x = 5, y = 10;
  printf("Before: x=%d, y=%d\n", x, y);
  swap(&x, &y);
  printf("After: x=%d, y=%d\n", x, y);
  increment(&x);
  printf("After increment: x=%d\n", x);
  return 0;
}
